export default function UserProfile() {
  const { user } = useContext(AuthContext);

  const [savedArticles, setSavedArticles] = useState([]);
  const [savedResults, setSavedResults] = useState([]);
  const [recommendedArticles, setRecommendedArticles] = useState([]);
  const [dbMBTI, setDbMBTI] = useState("DEFAULT");

  const sidebarRef = useRef(null);

  const [memory] = useState({
    lastGoal: localStorage.getItem("lastGoal") || "",
    lastInterest: localStorage.getItem("lastInterest") || "",
    lastTone: localStorage.getItem("lastTone") || "neutral",
    lastEmotion: localStorage.getItem("lastEmotion") || "neutral"
  });

  // ✅ 1️⃣ წამოიღე MBTI პირდაპირ DB-დან
  useEffect(() => {
    const fetchMBTI = async () => {
      try {
        const token = localStorage.getItem("auth_token");
        if (!token) return;

        const res = await fetch("http://localhost:5000/api/user/me", {
          headers: { Authorization: `Bearer ${token}` }
        });

        if (!res.ok) return;

        const data = await res.json();

        if (data.mbtiType && data.mbtiType !== "Unknown") {
          setDbMBTI(data.mbtiType);
        }
      } catch (err) {
        console.error("MBTI fetch error:", err);
      }
    };

    fetchMBTI();
  }, []);

  // Load saved articles
  useEffect(() => {
    const articles = JSON.parse(localStorage.getItem("savedArticles")) || [];
    setSavedArticles(articles);
  }, []);

  // რეკომენდაციები უკვე DB MBTI-ზე
  useEffect(() => {
    if (!dbMBTI || dbMBTI === "DEFAULT") return;

    fetch(`http://localhost:5000/api/articles?type=${dbMBTI}`)
      .then(res => res.json())
      .then(data => setRecommendedArticles(data || []))
      .catch(() => setRecommendedArticles([]));
  }, [dbMBTI]);

  if (!user) return null;

  const userPhoto = user.photo
    ? user.photo.replace("http:", "https:")
    : "/images/default.png";

  return (
    <section className="profile-page">
      <div className="profile-left">
        <img
          src={userPhoto}
          alt={user.email}
          className="profile-avatar"
          onError={(e) => (e.target.src = "/images/default.png")}
        />
        <span className="profile-email">{user.email}</span>

        {/* 🔥 ახლა ჩატი იღებს პირდაპირ DB MBTI-ს */}
        <PersonalAIMentor
          userType={dbMBTI}
          userId={user._id}
          memory={memory}
        />
      </div>

      {recommendedArticles.length > 0 && (
        <div className="profile-articles-sidebar" ref={sidebarRef}>
          <h3 className="sidebar-title">
            შენთვის რეკომენდებული სტატიები
          </h3>

          {recommendedArticles.map(a => (
            <Link key={a.slug} to={`/articles/${a.slug}`} className="article-card">
              <img
                className="article-thumb"
                alt={a.title}
                src={a.image ? `http://localhost:5000${a.image}` : "/images/default.png"}
              />
              <div className="article-info">
                <b>{a.title}</b>
                <p>{a.excerpt}</p>
              </div>
            </Link>
          ))}
        </div>
      )}
    </section>
  );
}
